ALL_MODULES: List[Dict[str, Any]] = TIER_A_MODULES + TIER_B_MODULES + TIER_C_MODULES


def get_tier_modules(tier: str) -> List[Dict[str, Any]]:
    """Вернуть список модулей указанного тира ('A'|'B'|'C')."""
    mapping = {"A": TIER_A_MODULES, "B": TIER_B_MODULES, "C": TIER_C_MODULES}
    return mapping.get(tier, [])


def get_module_info(module_name: str) -> Optional[Dict[str, Any]]:
    """Найти запись реестра по имени модуля."""
    for entry in ALL_MODULES:
        if entry.get("module") == module_name:
            return entry
    return None


def tier_counts() -> Dict[str, int]:
    """Счётчики модулей по тирам."""
    return {"A": len(TIER_A_MODULES), "B": len(TIER_B_MODULES), "C": len(TIER_C_MODULES)}
